#include <bits/stdc++.h>
using namespace std;

const int mod=1e9+9;

int n,a[1<<20],b[1<<20],ones[1<<20],f[1<<20][21],g[1<<20][21],h[1<<20][21];

void add(int &x,long long y){x=(x+y)%mod;}

int main(){
    scanf("%d",&n);
    for(int i=0;i<1<<n;i++)
        scanf("%d",&a[i]);
    for(int i=0;i<1<<n;i++)
        scanf("%d",&b[i]);
    for(int i=1;i<1<<n;i++)
        ones[i]=ones[i-(i&(-i))]+1;
    for(int i=0;i<1<<n;i++){
        f[i][ones[i]]=a[i];
        g[i][ones[i]]=b[i];
    }
    for(int i=0;i<n;i++)
        for(int j=0;j<1<<n;j++)
            if((j>>i)&1)
                for(int k=0;k<=n;k++){
                    add(f[j][k],f[j-(1<<i)][k]);
                    add(g[j][k],g[j-(1<<i)][k]);
                }
    for(int i=0;i<1<<n;i++)
        for(int j=1;j<=n;j++){
            add(f[i][j],f[i][j-1]);
            add(g[i][j],g[i][j-1]);
        }
    for(int i=0;i<1<<n;i++)
        for(int j=0;j<=n;j++)
            for(int k=0;k<=j;k++)
                add(h[i][j],1ll*f[i][k]*g[i][j-k]);
    for(int i=0;i<n;i++)
        for(int j=0;j<1<<n;j++)
            if((j>>i)&1)
                for(int k=0;k<=n;k++)
                    add(h[j][k],mod-h[j-(1<<i)][k]);
    for(int i=0;i<1<<n;i++)
        for(int j=n;j;j--)
            add(h[i][j],mod-h[i][j-1]);
    for(int i=0;i<1<<n;i++)
        printf("%d ",h[i][ones[i]]);
    return 0;
}
